#include &lt;cstring&gt;

using namespace std;

void size_of(char arr[])
&#123;
    cout &lt;&lt; sizeof(arr) &lt;&lt; endl; &#x2F;&#x2F; warning: &#39;sizeof&#39; on array function parameter &#39;arr&#39; will return size of &#39;char*&#39; .
    cout &lt;&lt; strlen(arr) &lt;&lt; endl; 
&#125;

int main()
&#123;
    char arr[20] &#x3D; &quot;hello&quot;;
    size_of(arr); 
    return 0;
&#125;
