oneapi::tbb::concurrent_lru_cache&lt;int, std::string> cache(load_from_db, 100);

// handle 持有 value 的引用，保证使用期间不被淘汰
auto handle = cache[42];
if (handle) &#123;
    std::cout &lt;&lt; handle.value() &lt;&lt; std::endl;
&#125; // handle 析构，引用计数减 1

