简介本文将谈一谈并发队列，讲解集中可手写的并发队列的实现方式，以及介绍几种开源并发队列的实现，当然都是c++版本的。可手撸的并发队列实现起来相对简单，面试的时候可以撸一撸，简单生产环境也可以用一用；当然，实际生产环境中，还是建议直接用高性能的开源实现。可手撸的版本包括，单锁队列、双锁队列、原子队列；开源并发队列包括boost中的并发队列、tbb中的并发队列、folly中的并发队列、moodycamel中的并发队列。
单锁队列实现单锁队列是一种实现简单的并发队列，它通过一个锁控制入队和出队，通过两个条件变量分别控制队列空和队列满。数据入队之前判断队列是否满，如果满了，则等待full条件变量；出队前判断队列是否为空，如果为空，则等待empty条件变量。当队列满时出队则唤醒full条件变量；当队列为空并入队时，唤醒empty条件变量。
代码如下:
#pragma once

#include &lt;queue&gt;
#include &lt;vector&gt;
#include &lt;mutex&gt;
#include &lt;condition_variable&gt;

class BlockedQueue &#123;
 public:
  explicit BlockedQueue(size_t capacity) : capacity_(capacity) &#123;&#125;

  bool TryPush(int value) &#123;
    std::unique_lock lock(mutex_);
    if (data_.size() &gt;&#x3D; capacity_) &#123;
      return false;
    &#125;
    Enqueue(value);
    return true;
  &#125;

  bool TryPop(int *value) &#123;
    if (value &#x3D;&#x3D; nullptr) &#123;
      return false;
    &#125;
    std::unique_lock lock(mutex_);
    if (!data_.empty()) &#123;
      return false;
    &#125;
    Dequeue(value);
    return true;
  &#125;

  void Push(int value) &#123;
    std::unique_lock lock(mutex_);
    if (data_.size() &gt;&#x3D; capacity_) &#123;
      full_.wait(lock);
    &#125;
    Enqueue(value);
  &#125;

  void Pop(int *value) &#123;
    if (value &#x3D;&#x3D; nullptr) &#123;
      return;
    &#125;
    std::unique_lock lock(mutex_);
    if (data_.empty()) &#123;
      empty_.wait(lock);
    &#125;
    Dequeue(value);
  &#125;
 private:
  void Enqueue(int value) &#123;
    data_.push(value);
    if (data_.size() &#x3D;&#x3D; 1) &#123;
      empty_.notify_one();
    &#125;
  &#125;

  void Dequeue(int* value) &#123;
    *value &#x3D; data_.front();
    data_.pop();
    if (data_.size() &#x3D;&#x3D; capacity_ - 1) &#123;
      full_.notify_one();
    &#125;
  &#125;

 private:
  std::mutex mutex_;
  std::condition_variable full_;
  std::condition_variable empty_;
  std::queue&lt;int&gt; data_;
  const size_t capacity_;
&#125;;

上面的实现可以用单链表代替std::queue。这种结构实现简单，临界区较小，可以在请求维度的数据中使用。
双锁队列实现双锁队列是另一种并发队列，使用两把锁分别控制入队和出队，性能相较于单锁的稍微强点。双锁队列还包括两个条件变量，分别用于表示队列满和队列空；同时还拥有一个原子变量记录当前队列长度。入队列时，先等待“非满”条件变量，然后入队列，如果队列没满，则唤醒“非满”变量。如果入队前队列是空的，入队后就要唤醒“非空”变量。出队时，先等待“非空”条件变量，然后出队，如果队列还有数据，则唤醒“非空”变量。如果出队之前队列时非空的，则出队后唤醒“非满”变量。
代码如下:
#pragma once

#include &lt;atomic&gt;
#include &lt;mutex&gt;
#include &lt;condition_variable&gt;

struct Node &#123;
  int val;
  Node* next&#123;nullptr&#125;;
  explicit Node(int value &#x3D; 0): val(value) &#123; &#125;
&#125;;

class LinkedBlockQueue &#123;
 public:
  LinkedBlockQueue(size_t size): capacity_(size) &#123;
    head_ &#x3D; new Node;
    tail_ &#x3D; head_;
  &#125;

  bool TryPush(int value) &#123;
    if (count_.load() &gt;&#x3D; capacity_) &#123;
      return false;
    &#125;
    std::unique_lock lock(push_mutex_);
    Enqueue(value);
    auto current &#x3D; count_.fetch_add(1);
    if (current + 1 &lt; capacity_) &#123;
      not_full_.notify_one();
    &#125;
    if (current &#x3D;&#x3D; 0) &#123;
      NotifyNotEmpty();
    &#125;

    return true;
  &#125;

  bool TryPop(int* value) &#123;
    if (value &#x3D;&#x3D; nullptr) &#123;
      return false;
    &#125;
    if (count_.load() &#x3D;&#x3D; 0) &#123;
      return false;
    &#125;
    std::unique_lock lock(pop_mutex_);
    Dequeue(value);
    auto current &#x3D; count_.fetch_sub(1);
    if (current - 1 &#x3D;&#x3D; 0) &#123;
      not_empty_.notify_one();
    &#125;
    if (current &#x3D;&#x3D; capacity_) &#123;
      NotifyNotFull();
    &#125;

    return true;
  &#125;

  void Push(int value) &#123;
    size_t current &#x3D; 0;
    &#123;
      std::unique_lock lock(push_mutex_);
      not_full_.wait(lock, [&amp;]()&#123; return count_.load() &lt; capacity_;&#125;);
      Enqueue(value);
      current &#x3D; count_.fetch_add(1);
      if (current - 1 &lt; capacity_) &#123;
        not_full_.notify_one();
      &#125;
    &#125;
    if (current &#x3D;&#x3D; 0) &#123;
      NotifyNotEmpty();
    &#125;
  &#125;

  void Pop(int* value) &#123;
    if (value &#x3D;&#x3D; nullptr) &#123;
      return;
    &#125;
    size_t current &#x3D; 0;
    &#123;
      std::unique_lock lock(pop_mutex_);
      not_empty_.wait(lock, [&amp;]()&#123; return count_.load() &gt; 0; &#125;);
      Dequeue(value);
      current &#x3D; count_.fetch_sub(1);
      if (current &gt; 1) &#123;
        not_empty_.notify_one();
      &#125;
    &#125;
    if (current &#x3D;&#x3D; capacity_) &#123;
      NotifyNotFull();
    &#125;
  &#125;

 private:
  void Enqueue(int value) &#123;
    tail_-&gt;next &#x3D; new Node(value);
    tail_ &#x3D; tail_-&gt;next;
  &#125;

  void Dequeue(int* value) &#123;
    auto* node &#x3D; head_-&gt;next;
    *value &#x3D; node-&gt;val;
    head_-&gt;next &#x3D; node-&gt;next;
    delete node;
  &#125;

  void NotifyNotFull() &#123;
    std::unique_lock lock(push_mutex_);
    not_full_.notify_one();
  &#125;

  void NotifyNotEmpty() &#123;
    std::unique_lock lock(pop_mutex_);
    not_empty_.notify_one();
  &#125;

 private:
  Node* head_;
  Node* tail_;
  std::mutex push_mutex_;
  std::mutex pop_mutex_;
  std::condition_variable not_full_;
  std::condition_variable not_empty_;
  const size_t capacity_;
  std::atomic_size_t count_&#123;0&#125;;
&#125;;

代码稍微复杂一点，不过还是可以手工实现的。
